import * as React from "react";

import { Callback, PLUGIN_ZOOM, RenderFunction } from "../../index.js";
import { Zoom } from "./Zoom.js";

declare module "../../types.js" {
  interface LightboxProps {
    /** Zoom plugin settings */
    zoom?: {
      /** Zoom plugin ref */
      ref?: React.ForwardedRef<ZoomRef>;
      /** override minimum zoom level (default: 1.0) */
      minZoom?: number;
      /** ratio of image pixels to physical pixels at maximum zoom level */
      maxZoomPixelRatio?: number;
      /** zoom-in multiplier */
      zoomInMultiplier?: number;
      /** @deprecated - double-tap maximum time delay */
      doubleTapDelay?: number;
      /** @deprecated - double-click maximum time delay */
      doubleClickDelay?: number;
      /** maximum number of zoom-in stops via double-click or double-tap */
      doubleClickMaxStops?: number;
      /** keyboard move distance */
      keyboardMoveDistance?: number;
      /** wheel zoom distance factor */
      wheelZoomDistanceFactor?: number;
      /** @deprecated - pinch zoom distance factor */
      pinchZoomDistanceFactor?: number;
      /** if `true`, enables the experimental pinch zoom implementation slated for v4 */
      pinchZoomV4?: boolean;
      /** if `true`, enables image zoom via scroll gestures for mouse and trackpad users */
      scrollToZoom?: boolean;
    };
  }

  // noinspection JSUnusedGlobalSymbols
  interface AnimationSettings {
    /** zoom animation duration */
    zoom?: number;
  }

  interface Render {
    /** render custom Zoom control in the toolbar */
    buttonZoom?: RenderFunction<ZoomRef>;
    /** render custom Zoom In icon */
    iconZoomIn?: RenderFunction;
    /** render custom Zoom Out icon */
    iconZoomOut?: RenderFunction;
  }

  interface Labels {
    /** `Zoom in` button title */
    "Zoom in"?: string;
    /** `Zoom out` button title */
    "Zoom out"?: string;
  }

  // noinspection JSUnusedGlobalSymbols
  interface RenderSlideProps {
    /** current zoom level */
    zoom?: number;
    /** maximum zoom level */
    maxZoom?: number;
  }

  // noinspection JSUnusedGlobalSymbols
  interface Callbacks {
    /** zoom callback */
    zoom?: Callback<ZoomCallbackProps>;
  }

  /** Zoom callback props */
  interface ZoomCallbackProps {
    /** current zoom level */
    zoom: number;
  }

  // noinspection JSUnusedGlobalSymbols
  interface ToolbarButtonKeys {
    [PLUGIN_ZOOM]: null;
  }

  /** Zoom plugin ref */
  interface ZoomRef {
    /** current zoom level */
    zoom: number;
    /** minimum zoom level */
    minZoom: number;
    /** maximum zoom level */
    maxZoom: number;
    /** horizontal offset */
    offsetX: number;
    /** vertical offset */
    offsetY: number;
    /** if `true`, zoom is unavailable for the current slide */
    disabled: boolean;
    /** increase zoom level using `zoomInMultiplier` */
    zoomIn: Callback;
    /** decrease zoom level using `zoomInMultiplier` */
    zoomOut: Callback;
    /** change zoom level */
    changeZoom: (targetZoom: number, rapid?: boolean, dx?: number, dy?: number) => void;
  }
}

export default Zoom;

--- props ---
import { LightboxProps } from "../../index.js";

export const defaultZoomProps = {
  minZoom: 1,
  maxZoomPixelRatio: 1,
  zoomInMultiplier: 2,
  doubleTapDelay: 300,
  doubleClickDelay: 500,
  doubleClickMaxStops: 2,
  keyboardMoveDistance: 50,
  wheelZoomDistanceFactor: 100,
  pinchZoomDistanceFactor: 100,
  pinchZoomV4: false,
  scrollToZoom: false,
};

function validateMinZoom(minZoom: number) {
  return Math.min(Math.max(minZoom, Number.EPSILON), 1);
}

export function resolveZoomProps(zoom: LightboxProps["zoom"]) {
  const { minZoom, ...rest } = { ...defaultZoomProps, ...zoom };
  return { minZoom: validateMinZoom(minZoom), ...rest };
}

--- zoom props hook ---
import { useLightboxProps } from "../../../index.js";
import { resolveZoomProps } from "../props.js";

export function useZoomProps() {
  const { zoom } = useLightboxProps();
  return resolveZoomProps(zoom);
}

import * as React from "react";

import {
  ContainerRect,
  isImageSlide,
  round,
  useController,
  useEventCallback,
  useLayoutEffect,
  useLightboxState,
} from "../../../index.js";
import { useZoomProps } from "./useZoomProps.js";
import { useZoomAnimation } from "./useZoomAnimation.js";

export function useZoomState(
  imageRect: ContainerRect,
  maxZoom: number,
  zoomWrapperRef?: React.RefObject<HTMLDivElement | null>,
) {
  const [zoom, setZoom] = React.useState(1);
  const [offsetX, setOffsetX] = React.useState(0);
  const [offsetY, setOffsetY] = React.useState(0);

  const animate = useZoomAnimation(zoom, offsetX, offsetY, zoomWrapperRef);

  const { currentSlide, globalIndex } = useLightboxState();
  const { containerRect, slideRect } = useController();
  const { minZoom, zoomInMultiplier } = useZoomProps();

  const currentSource = currentSlide && isImageSlide(currentSlide) ? currentSlide.src : undefined;
  const disabled = !currentSource || !zoomWrapperRef?.current;

  useLayoutEffect(() => {
    setZoom(1);
    setOffsetX(0);
    setOffsetY(0);
  }, [globalIndex, currentSource]);

  const changeOffsets = React.useCallback(
    (dx?: number, dy?: number, targetZoom?: number) => {
      const newZoom = targetZoom || zoom;

      const newOffsetX = offsetX - (dx || 0);
      const newOffsetY = offsetY - (dy || 0);

      const maxOffsetX = (imageRect.width * newZoom - slideRect.width) / 2 / newZoom;
      const maxOffsetY = (imageRect.height * newZoom - slideRect.height) / 2 / newZoom;

      setOffsetX(Math.min(Math.abs(newOffsetX), Math.max(maxOffsetX, 0)) * Math.sign(newOffsetX));
      setOffsetY(Math.min(Math.abs(newOffsetY), Math.max(maxOffsetY, 0)) * Math.sign(newOffsetY));
    },
    [zoom, offsetX, offsetY, slideRect, imageRect.width, imageRect.height],
  );

  const changeZoom = React.useCallback(
    (targetZoom: number, rapid?: boolean, dx?: number, dy?: number) => {
      const newZoom = round(
        targetZoom + 0.01 < maxZoom ? (targetZoom - 0.01 > minZoom ? targetZoom : minZoom) : maxZoom,
        5,
      );

      if (!rapid) {
        animate();
      }

      changeOffsets(dx ? dx * (1 / zoom - 1 / newZoom) : 0, dy ? dy * (1 / zoom - 1 / newZoom) : 0, newZoom);

      setZoom(newZoom);
    },
    [zoom, minZoom, maxZoom, changeOffsets, animate],
  );

  const handleControllerRectChange = useEventCallback(() => {
    if (zoom > 1) {
      if (zoom > maxZoom) {
        changeZoom(maxZoom, true);
      }

      changeOffsets();
    }
  });

  useLayoutEffect(handleControllerRectChange, [containerRect.width, containerRect.height, handleControllerRectChange]);

  const zoomIn = React.useCallback(() => {
    const targetZoom = zoom * zoomInMultiplier;
    changeZoom(zoom < 1 && targetZoom > 1 ? 1 : targetZoom);
  }, [zoom, zoomInMultiplier, changeZoom]);

  const zoomOut = React.useCallback(() => {
    const targetZoom = zoom / zoomInMultiplier;
    changeZoom(zoom > 1 && targetZoom < 1 ? 1 : targetZoom);
  }, [zoom, zoomInMultiplier, changeZoom]);

  return { zoom, offsetX, offsetY, disabled, changeOffsets, changeZoom, zoomIn, zoomOut };
}

--- image rect ---
import {
  ContainerRect,
  isImageFitCover,
  isImageSlide,
  round,
  useLightboxProps,
  useLightboxState,
} from "../../../index.js";
import { useZoomProps } from "./useZoomProps.js";

export function useZoomImageRect(slideRect: ContainerRect, imageDimensions?: ContainerRect) {
  let imageRect: ContainerRect = { width: 0, height: 0 };
  let maxImageRect: ContainerRect = { width: 0, height: 0 };

  const { currentSlide } = useLightboxState();
  const { imageFit } = useLightboxProps().carousel;
  const { maxZoomPixelRatio } = useZoomProps();

  if (slideRect && currentSlide) {
    const slide = { ...currentSlide, ...imageDimensions };
    if (isImageSlide(slide)) {
      const cover = isImageFitCover(slide, imageFit);

      const width = Math.max(...(slide.srcSet?.map((x) => x.width) || []).concat(slide.width ? [slide.width] : []));

      const height = Math.max(...(slide.srcSet?.map((x) => x.height) || []).concat(slide.height ? [slide.height] : []));

      if (width > 0 && height > 0 && slideRect.width > 0 && slideRect.height > 0) {
        maxImageRect = cover
          ? {
              width: Math.round(Math.min(width, (slideRect.width / slideRect.height) * height)),
              height: Math.round(Math.min(height, (slideRect.height / slideRect.width) * width)),
            }
          : { width, height };

        maxImageRect = {
          width: maxImageRect.width * maxZoomPixelRatio,
          height: maxImageRect.height * maxZoomPixelRatio,
        };

        imageRect = cover
          ? {
              width: Math.min(slideRect.width, maxImageRect.width, width),
              height: Math.min(slideRect.height, maxImageRect.height, height),
            }
          : {
              width: Math.round(Math.min(slideRect.width, (slideRect.height / height) * width, width)),
              height: Math.round(Math.min(slideRect.height, (slideRect.width / width) * height, height)),
            };
      }
    }
  }

  const maxZoom = imageRect.width ? Math.max(round(maxImageRect.width / imageRect.width, 5), 1) : 1;

  return { imageRect, maxZoom };
}

--- sensors ---
import * as React from "react";

import {
  cleanup,
  EVENT_ON_KEY_DOWN,
  EVENT_ON_WHEEL,
  useController,
  useDocumentContext,
  useEventCallback,
  useLightboxState,
} from "../../../index.js";
import { useZoomProps } from "./useZoomProps.js";
import { useZoomState } from "./useZoomState.js";
import { usePointerEvents } from "../../../hooks/usePointerEvents.js";

function distance(pointerA: React.MouseEvent, pointerB: React.MouseEvent) {
  return Math.hypot(pointerA.clientX - pointerB.clientX, pointerA.clientY - pointerB.clientY);
}

function scaleZoom(value: number, delta: number, factor = 100, clamp = 2) {
  return value * Math.min(1 + Math.abs(delta / factor), clamp) ** Math.sign(delta);
}

export function useZoomSensors(
  zoom: number,
  minZoom: number,
  maxZoom: number,
  disabled: boolean,
  zoomIn: ReturnType<typeof useZoomState>["zoomIn"],
  zoomOut: ReturnType<typeof useZoomState>["zoomOut"],
  changeZoom: ReturnType<typeof useZoomState>["changeZoom"],
  changeOffsets: ReturnType<typeof useZoomState>["changeOffsets"],
  zoomWrapperRef?: React.RefObject<HTMLDivElement | null>,
) {
  const activePointers = React.useRef<React.PointerEvent[]>([]);
  const lastPointerDown = React.useRef(0);
  const pinchZoom = React.useRef<{
    previousDistance: number;
    initialDistance: number;
    initialZoom: number;
  }>(undefined);

  const { globalIndex } = useLightboxState();
  const { getOwnerWindow } = useDocumentContext();
  const { containerRef, subscribeSensors } = useController();
  const {
    keyboardMoveDistance,
    zoomInMultiplier,
    wheelZoomDistanceFactor,
    scrollToZoom,
    doubleTapDelay,
    doubleClickDelay,
    doubleClickMaxStops,
    pinchZoomDistanceFactor,
    pinchZoomV4,
  } = useZoomProps();

  const translateCoordinates = React.useCallback(
    (event: React.MouseEvent) => {
      if (containerRef.current) {
        const { pageX, pageY } = event;
        const { scrollX, scrollY } = getOwnerWindow();
        const { left, top, width, height } = containerRef.current.getBoundingClientRect();
        return [pageX - left - scrollX - width / 2, pageY - top - scrollY - height / 2];
      }
      return [];
    },
    [containerRef, getOwnerWindow],
  );

  const onKeyDown = useEventCallback((event: React.KeyboardEvent) => {
    const { key, metaKey, ctrlKey } = event;
    const meta = metaKey || ctrlKey;

    const preventDefault = () => {
      event.preventDefault();
      event.stopPropagation();
    };

    if (zoom > 1) {
      const move = (deltaX: number, deltaY: number) => {
        preventDefault();
        changeOffsets(deltaX, deltaY);
      };

      if (key === "ArrowDown") {
        move(0, keyboardMoveDistance);
      } else if (key === "ArrowUp") {
        move(0, -keyboardMoveDistance);
      } else if (key === "ArrowLeft") {
        move(-keyboardMoveDistance, 0);
      } else if (key === "ArrowRight") {
        move(keyboardMoveDistance, 0);
      }
    }

    if (key === "+" || (meta && key === "=")) {
      preventDefault();
      zoomIn();
    } else if (key === "-" || (meta && key === "_")) {
      preventDefault();
      zoomOut();
    } else if (meta && key === "0") {
      preventDefault();
      changeZoom(1);
    }
  });

  const onWheel = useEventCallback((event: React.WheelEvent) => {
    if (event.ctrlKey || scrollToZoom) {
      if (Math.abs(event.deltaY) > Math.abs(event.deltaX)) {
        event.stopPropagation();

        changeZoom(scaleZoom(zoom, -event.deltaY, wheelZoomDistanceFactor), true, ...translateCoordinates(event));

        return;
      }
    }

    if (zoom > 1) {
      event.stopPropagation();

      if (!scrollToZoom) {
        changeOffsets(event.deltaX, event.deltaY);
      }
    }
  });

  const clearPointer = React.useCallback((event: React.PointerEvent) => {
    const pointers = activePointers.current;
    pointers.splice(0, pointers.length, ...pointers.filter((p) => p.pointerId !== event.pointerId));
  }, []);

  const replacePointer = React.useCallback(
    (event: React.PointerEvent) => {
      clearPointer(event);
      event.persist();
      activePointers.current.push(event);
    },
    [clearPointer],
  );

  const onPointerDown = useEventCallback((event: React.PointerEvent) => {
    const pointers = activePointers.current;

    if (
      // ignore right button clicks (e.g., context menu)
      (event.pointerType === "mouse" && event.buttons > 1) ||
      // ignore clicks outside current slide (zoom icons, navigation buttons, etc.)
      !zoomWrapperRef?.current?.contains(event.target as unknown as Element)
    ) {
      return;
    }

    if (zoom > 1) {
      event.stopPropagation();
    }

    const { timeStamp } = event;
    if (
      pointers.length === 0 &&
      timeStamp - lastPointerDown.current < (event.pointerType === "touch" ? doubleTapDelay : doubleClickDelay)
    ) {
      lastPointerDown.current = 0;

      const targetZoom =
        zoom >= 1
          ? zoom !== maxZoom
            ? zoom * Math.max(maxZoom ** (1 / doubleClickMaxStops), zoomInMultiplier)
            : 1
          : zoom !== minZoom
            ? zoom / Math.max(minZoom ** (-1 / doubleClickMaxStops), zoomInMultiplier)
            : 1;

      changeZoom(targetZoom, false, ...translateCoordinates(event));
    } else {
      lastPointerDown.current = timeStamp;
    }

    replacePointer(event);

    if (pointers.length === 2) {
      const initialDistance = distance(pointers[0], pointers[1]);
      pinchZoom.current = {
        previousDistance: initialDistance,
        initialDistance: Math.max(initialDistance, 1), // prevent potential division by zero
        initialZoom: zoom,
      };
    }
  });

  const onPointerMove = useEventCallback((event: React.PointerEvent) => {
    const pointers = activePointers.current;

    const activePointer = pointers.find((p) => p.pointerId === event.pointerId);

    if (pointers.length === 2 && pinchZoom.current) {
      event.stopPropagation();

      replacePointer(event);

      const currentDistance = distance(pointers[0], pointers[1]);

      // TODO v4: remove `pinchZoomV4` flag and make this the default behavior
      const targetZoom = pinchZoomV4
        ? (pinchZoom.current.initialZoom / pinchZoom.current.initialDistance) * currentDistance
        : scaleZoom(zoom, currentDistance - pinchZoom.current.previousDistance, pinchZoomDistanceFactor);

      changeZoom(
        targetZoom,
        true,
        ...pointers
          .map((x) => translateCoordinates(x))
          .reduce((acc, coordinate) => coordinate.map((x, i) => acc[i] + x / 2)),
      );

      pinchZoom.current.previousDistance = currentDistance;

      return;
    }

    if (zoom > 1) {
      event.stopPropagation();

      if (activePointer) {
        if (pointers.length === 1) {
          changeOffsets((activePointer.clientX - event.clientX) / zoom, (activePointer.clientY - event.clientY) / zoom);
        }

        replacePointer(event);
      }
    }
  });

  const onPointerUp = React.useCallback(
    (event: React.PointerEvent) => {
      const pointers = activePointers.current;

      if (pointers.length === 2 && pointers.find((p) => p.pointerId === event.pointerId)) {
        pinchZoom.current = undefined;
      }

      clearPointer(event);
    },
    [clearPointer],
  );

  const cleanupSensors = React.useCallback(() => {
    const pointers = activePointers.current;
    pointers.splice(0, pointers.length);

    lastPointerDown.current = 0;
    pinchZoom.current = undefined;
  }, []);

  usePointerEvents(subscribeSensors, onPointerDown, onPointerMove, onPointerUp, disabled);

  React.useEffect(cleanupSensors, [globalIndex, cleanupSensors]);

  React.useEffect(() => {
    if (!disabled) {
      return cleanup(
        cleanupSensors,
        subscribeSensors(EVENT_ON_KEY_DOWN, onKeyDown),
        subscribeSensors(EVENT_ON_WHEEL, onWheel),
      );
    }
    return () => {};
  }, [disabled, subscribeSensors, cleanupSensors, onKeyDown, onWheel]);
}

import { act, render, screen } from "@testing-library/react";

import { lightbox, expectLightboxToBeOpen } from "../test-utils.js";
import { Zoom } from "../../../src/plugins/index.js";

describe("Zoom", () => {
  it("renders without crashing", async () => {
    render(
      lightbox({
        slides: Array.from({ length: 3 }).map((_, i) => ({
          src: `image${i + 1}`,
          width: 3000,
          height: 2000,
        })),
        plugins: [Zoom],
      }),
    );

    act(() => {
      screen.getByLabelText("Zoom in").click();
    });

    act(() => {
      screen.getByLabelText("Zoom out").click();
    });

    expectLightboxToBeOpen();
  });
});

